        SexoParameter.Value.Should().Be(SexoValue);
        // Check where clause
        result.Value.where.Should().Contain($"[{DBColaboradoresDicInfo.PTabelaNome}].[{DBColaboradoresDicInfo.Sexo}] = @{DBColaboradoresDicInfo.Sexo}");
    }

